import random
import time
from collections import defaultdict
from dataclasses import dataclass, field
from enum import Enum
from typing import List, Dict, Set, Optional
import matplotlib.pyplot as plt
import numpy as np

class Direction(Enum):
    UP = 1
    DOWN = -1
    IDLE = 0

@dataclass
class Elevator:
    id: int
    current_floor: int = 0
    direction: Direction = Direction.IDLE
    destination_floors: List[int] = field(default_factory=list)
    passengers: Set[int] = field(default_factory=set)
    capacity: int = 10

    def add_destination(self, floor: int):
        if floor not in self.destination_floors:
            self.destination_floors.append(floor)
            self.destination_floors.sort(reverse=(self.direction == Direction.DOWN))

    def move(self):
        if not self.destination_floors:
            self.direction = Direction.IDLE
            return

        next_floor = self.destination_floors[0]
        if self.current_floor < next_floor:
            self.direction = Direction.UP
            self.current_floor += 1
        elif self.current_floor > next_floor:
            self.direction = Direction.DOWN
            self.current_floor -= 1
        else:
            self.destination_floors.pop(0)

    def has_arrived(self) -> bool:
        return self.current_floor in self.destination_floors

    def can_pickup(self, floor: int, direction: Direction) -> bool:
        if self.direction == Direction.IDLE:
            return True
        if self.direction != direction:
            return False
        if direction == Direction.UP and floor >= self.current_floor:
            return True
        if direction == Direction.DOWN and floor <= self.current_floor:
            return True
        return False

@dataclass
class Passenger:
    id: int
    current_floor: int
    destination_floor: int
    direction: Direction = Direction.IDLE
    in_elevator: bool = False
    waiting_since: float = 0.0

    def update_direction(self):
        if self.destination_floor > self.current_floor:
            self.direction = Direction.UP
        elif self.destination_floor < self.current_floor:
            self.direction = Direction.DOWN
        else:
            self.direction = Direction.IDLE

class Building:
    def __init__(self, num_floors: int, num_elevators: int):
        self.num_floors = num_floors
        self.elevators = [Elevator(i) for i in range(num_elevators)]
        self.passengers: Dict[int, Passenger] = {}
        self.waiting_up: Dict[int, List[Passenger]] = defaultdict(list)
        self.waiting_down: Dict[int, List[Passenger]] = defaultdict(list)
        self.time: float = 0.0
        self.passenger_counter = 0
        self.stats = {
            'wait_times': [],
            'trips_completed': 0,
            'elevator_movements': 0
        }

    def add_passenger(self, current_floor: int, destination_floor: int):
        if current_floor == destination_floor:
            return
        passenger = Passenger(
            id=self.passenger_counter,
            current_floor=current_floor,
            destination_floor=destination_floor
        )
        passenger.update_direction()
        self.passenger_counter += 1
        self.passengers[passenger.id] = passenger
        if passenger.direction == Direction.UP:
            self.waiting_up[current_floor].append(passenger)
        else:
            self.waiting_down[current_floor].append(passenger)
        passenger.waiting_since = self.time

    def assign_elevator(self, floor: int, direction: Direction) -> Optional[Elevator]:
        best_elevator = None
        min_distance = float('inf')

        for elevator in self.elevators:
            if not elevator.can_pickup(floor, direction):
                continue
            distance = abs(elevator.current_floor - floor)
            if distance < min_distance:
                min_distance = distance
                best_elevator = elevator

        if best_elevator:
            best_elevator.add_destination(floor)
            return best_elevator
        return None

    def update_elevators(self):
        for elevator in self.elevators:
            prev_floor = elevator.current_floor
            elevator.move()
            if prev_floor != elevator.current_floor:
                self.stats['elevator_movements'] += 1

            if elevator.has_arrived():
                floor = elevator.current_floor
                passengers_to_unload = [p for p in elevator.passengers if p.destination_floor == floor]
                for passenger in passengers_to_unload:
                    passenger.in_elevator = False
                    passenger.current_floor = floor
                    self.stats['trips_completed'] += 1
                    self.stats['wait_times'].append(self.time - passenger.waiting_since)
                    del self.passengers[passenger.id]
                elevator.passengers.difference_update(passengers_to_unload)

                waiting_list = self.waiting_up[floor] if elevator.direction == Direction.UP else self.waiting_down[floor]
                passengers_to_load = []
                for passenger in waiting_list[:]:
                    if len(elevator.passengers) < elevator.capacity:
                        passengers_to_load.append(passenger)
                        waiting_list.remove(passenger)
                for passenger in passengers_to_load:
                    passenger.in_elevator = True
                    elevator.passengers.add(passenger)
                    elevator.add_destination(passenger.destination_floor)

    def step(self, time_increment: float = 1.0):
        self.time += time_increment
        self.update_elevators()

        for floor in range(self.num_floors):
            if self.waiting_up[floor]:
                self.assign_elevator(floor, Direction.UP)
            if self.waiting_down[floor]:
                self.assign_elevator(floor, Direction.DOWN)

def simulate_day(num_floors: int, num_elevators: int, crowd_size: int):
    building = Building(num_floors, num_elevators)
    day_length = 24 * 60  # minutes in a day
    stats_per_hour = []

    for minute in range(day_length):
        hour = minute // 60
        if 8 <= hour < 9 or 17 <= hour < 18:  # Rush hours
            if random.random() < 0.3 * crowd_size / 100:
                start = random.randint(0, num_floors - 1)
                end = random.randint(0, num_floors - 1)
                building.add_passenger(start, end)
        elif 9 <= hour < 17:  # Daytime
            if random.random() < 0.05 * crowd_size / 100:
                start = random.randint(0, num_floors - 1)
                end = random.randint(0, num_floors - 1)
                building.add_passenger(start, end)
        else:  # Nighttime
            if random.random() < 0.01 * crowd_size / 100:
                start = random.randint(0, num_floors - 1)
                end = random.randint(0, num_floors - 1)
                building.add_passenger(start, end)

        building.step()

        if minute % 60 == 0:  # Record stats every hour
            stats_per_hour.append({
                'hour': hour,
                'passengers_waiting': len(building.passengers),
                'elevators_moving': sum(1 for e in building.elevators if e.direction != Direction.IDLE),
                'trips_completed': building.stats['trips_completed']
            })

    return building.stats, stats_per_hour

def plot_stats(stats_per_hour):
    hours = [s['hour'] for s in stats_per_hour]
    waiting = [s['passengers_waiting'] for s in stats_per_hour]
    moving = [s['elevators_moving'] for s in stats_per_hour]
    trips = [s['trips_completed'] for s in stats_per_hour]

    plt.figure(figsize=(12, 8))
    plt.subplot(3, 1, 1)
    plt.plot(hours, waiting)
    plt.title('Passengers Waiting Over Time')
    plt.xlabel('Hour of Day')
    plt.ylabel('Passengers Waiting')

    plt.subplot(3, 1, 2)
    plt.plot(hours, moving)
    plt.title('Elevators Moving Over Time')
    plt.xlabel('Hour of Day')
    plt.ylabel('Elevators Moving')

    plt.subplot(3, 1, 3)
    plt.plot(hours, trips)
    plt.title('Trips Completed Over Time')
    plt.xlabel('Hour of Day')
    plt.ylabel('Trips Completed')

    plt.tight_layout()
    plt.show()

if __name__ == "__main__":
    num_floors = 20
    num_elevators = 4
    crowd_size = 200  # Percentage of maximum capacity

    stats, hourly_stats = simulate_day(num_floors, num_elevators, crowd_size)
    print(f"Simulation completed. Average wait time: {np.mean(stats['wait_times']):.2f} minutes")
    plot_stats(hourly_stats)

