import random
import time
import matplotlib.pyplot as plt
from collections import defaultdict

class Lift:
    def __init__(self, id, max_levels):
        self.id = id
        self.current_level = 0  # ground floor
        self.destination = None
        self.direction = 0  # 0: idle, 1: up, -1: down
        self.passengers = []
        self.max_levels = max_levels

    def move(self):
        if self.destination is None:
            return
        if self.current_level < self.destination:
            self.current_level += 1
            self.direction = 1
        elif self.current_level > self.destination:
            self.current_level -= 1
            self.direction = -1
        else:
            self.direction = 0
            self.destination = None

    def add_passenger(self, passenger):
        self.passengers.append(passenger)
        if self.destination is None or (
            (passenger.destination > self.current_level and passenger.destination > self.destination) or
            (passenger.destination < self.current_level and passenger.destination < self.destination)
        ):
            self.destination = passenger.destination

    def remove_passengers(self):
        passengers_to_remove = [p for p in self.passengers if p.destination == self.current_level]
        self.passengers = [p for p in self.passengers if p.destination != self.current_level]
        return passengers_to_remove

class Passenger:
    def __init__(self, id, current_level, destination):
        self.id = id
        self.current_level = current_level
        self.destination = destination

class Building:
    def __init__(self, num_lifts, num_levels, population):
        self.num_lifts = num_lifts
        self.num_levels = num_levels
        self.population = population
        self.lifts = [Lift(i, num_levels) for i in range(num_lifts)]
        self.levels = {level: [] for level in range(num_levels)}
        self.time = 0  # in minutes
        self.peak_hours = [8, 9, 17, 18]  # 8-9 AM and 5-6 PM
        self.stats = defaultdict(list)

    def generate_passengers(self):
        if self.time % 60 in self.peak_hours:
            num_new_passengers = random.randint(0, self.population // 10)
        else:
            num_new_passengers = random.randint(0, self.population // 20)

        for _ in range(num_new_passengers):
            current_level = random.randint(0, self.num_levels - 1)
            destination = random.randint(0, self.num_levels - 1)
            while destination == current_level:
                destination = random.randint(0, self.num_levels - 1)
            passenger = Passenger(len(self.levels[current_level]), current_level, destination)
            self.levels[current_level].append(passenger)

    def assign_passengers_to_lifts(self):
        for level, passengers in self.levels.items():
            if not passengers:
                continue
            for lift in self.lifts:
                if lift.current_level == level and lift.direction == 0:
                    passenger = passengers.pop(0)
                    lift.add_passenger(passenger)
                    if not passengers:
                        break

    def update_lifts(self):
        for lift in self.lifts:
            lift.move()
            arrived_passengers = lift.remove_passengers()
            if arrived_passengers:
                self.stats[lift.id].append((self.time, len(arrived_passengers)))

    def simulate_step(self):
        self.generate_passengers()
        self.assign_passengers_to_lifts()
        self.update_lifts()
        self.time += 1

    def visualize_usage(self):
        plt.figure(figsize=(10, 6))
        for lift_id, data in self.stats.items():
            if data:
                times, counts = zip(*data)
                plt.scatter(times, counts, label=f"Lift {lift_id}")
        plt.xlabel("Time (minutes)")
        plt.ylabel("Passengers Delivered")
        plt.title("Lift Usage Over Time")
        plt.legend()
        plt.grid()
        plt.show()

def main():
    num_lifts = 4
    num_levels = 20
    population = 1000

    building = Building(num_lifts, num_levels, population)

    for _ in range(24 * 60):  # Simulate 24 hours in minutes
        building.simulate_step()

    building.visualize_usage()

if __name__ == "__main__":
    main()

