import random
import time
from threading import Thread, Lock
from queue import Queue
import matplotlib.pyplot as plt
from matplotlib.animation import FuncAnimation

class Elevator:
    def __init__(self, id, total_floors):
        self.id = id
        self.current_floor = 1
        self.direction = 0  # 0: idle, 1: up, -1: down
        self.destination_floors = []
        self.occupants = 0
        self.max_occupants = 10
        self.lock = Lock()
        self.total_floors = total_floors

    def move(self):
        with self.lock:
            if not self.destination_floors:
                self.direction = 0
                return

            next_floor = self.destination_floors[0]
            if next_floor > self.current_floor:
                self.direction = 1
                self.current_floor += 1
            elif next_floor < self.current_floor:
                self.direction = -1
                self.current_floor -= 1
            else:
                self.direction = 0
                self.destination_floors.pop(0)

    def add_destination(self, floor):
        with self.lock:
            if floor not in self.destination_floors and 1 <= floor <= self.total_floors:
                self.destination_floors.append(floor)
                self.destination_floors.sort()

    def board_passenger(self):
        with self.lock:
            if self.occupants < self.max_occupants:
                self.occupants += 1
                return True
            return False

    def alight_passenger(self):
        with self.lock:
            if self.occupants > 0:
                self.occupants -= 1
                return True
            return False

class Building:
    def __init__(self, num_elevators, num_floors):
        self.elevators = [Elevator(i, num_floors) for i in range(num_elevators)]
        self.num_floors = num_floors
        self.floor_queues = {floor: {'up': Queue(), 'down': Queue()} for floor in range(1, num_floors + 1)}
        self.simulation_time = 0
        self.people_in_building = 0
        self.lock = Lock()

    def simulate_time_of_day(self):
        # Simulate different traffic patterns based on time of day
        hour = self.simulation_time % 24
        if 7 <= hour < 9:  # Morning rush
            return random.randint(5, 10)
        elif 16 <= hour < 18:  # Evening rush
            return random.randint(5, 10)
        elif 9 <= hour < 16:  # Daytime
            return random.randint(1, 3)
        else:  # Night
            return random.randint(0, 1)

    def generate_passengers(self):
        num_passengers = self.simulate_time_of_day()
        for _ in range(num_passengers):
            start_floor = random.randint(1, self.num_floors)
            if start_floor == 1:
                direction = 'up'
                end_floor = random.randint(2, self.num_floors)
            elif start_floor == self.num_floors:
                direction = 'down'
                end_floor = random.randint(1, self.num_floors - 1)
            else:
                direction = random.choice(['up', 'down'])
                if direction == 'up':
                    end_floor = random.randint(start_floor + 1, self.num_floors)
                else:
                    end_floor = random.randint(1, start_floor - 1)

            with self.lock:
                self.floor_queues[start_floor][direction].put(end_floor)
                self.people_in_building += 1

    def assign_elevators(self):
        for elevator in self.elevators:
            for floor in range(1, self.num_floors + 1):
                for direction in ['up', 'down']:
                    if not self.floor_queues[floor][direction].empty():
                        if (elevator.direction == 0 or 
                            (elevator.direction == 1 and floor >= elevator.current_floor) or 
                            (elevator.direction == -1 and floor <= elevator.current_floor)):
                            elevator.add_destination(floor)

    def update_elevators(self):
        for elevator in self.elevators:
            elevator.move()
            if elevator.current_floor in elevator.destination_floors:
                if elevator.alight_passenger():
                    with self.lock:
                        self.people_in_building -= 1

                floor = elevator.current_floor
                for direction in ['up', 'down']:
                    while not self.floor_queues[floor][direction].empty() and elevator.board_passenger():
                        end_floor = self.floor_queues[floor][direction].get()
                        elevator.add_destination(end_floor)

    def run_simulation_step(self):
        self.generate_passengers()
        self.assign_elevators()
        self.update_elevators()
        self.simulation_time += 1

class SimulationVisualization:
    def __init__(self, building):
        self.building = building
        self.fig, (self.ax1, self.ax2) = plt.subplots(2, 1, figsize=(10, 8))
        self.ax1.set_title('Elevator Positions')
        self.ax1.set_xlim(0, len(self.building.elevators) + 1)
        self.ax1.set_ylim(0, self.building.num_floors + 1)
        self.ax1.set_xlabel('Elevator ID')
        self.ax1.set_ylabel('Floor')

        self.ax2.set_title('People in Building Over Time')
        self.ax2.set_xlabel('Time (hours)')
        self.ax2.set_ylabel('People Count')
        self.time_data = []
        self.people_data = []

        self.elevator_plots = [self.ax1.plot([], [], 'o-', label=f'Elevator {i}')[0] 
                              for i in range(len(self.building.elevators))]
        self.people_plot, = self.ax2.plot([], [], 'r-')

    def update(self, frame):
        self.building.run_simulation_step()

        # Update elevator positions
        for i, elevator in enumerate(self.building.elevators):
            self.elevator_plots[i].set_data([i + 1], [elevator.current_floor])

        # Update people count graph
        self.time_data.append(self.building.simulation_time)
        self.people_data.append(self.building.people_in_building)
        self.people_plot.set_data(self.time_data, self.people_data)

        self.ax2.relim()
        self.ax2.autoscale_view()

        return self.elevator_plots + [self.people_plot]

def run_simulation(num_elevators=4, num_floors=20, simulation_duration=100):
