import random
import time
from threading import Thread, Lock
from queue import Queue

class Elevator:
    def __init__(self, id, total_floors):
        self.id = id
        self.current_floor = 1
        self.direction = 0  # 0: idle, 1: up, -1: down
        self.destination_floors = []
        self.lock = Lock()
        self.total_floors = total_floors

    def move(self):
        with self.lock:
            if not self.destination_floors:
                self.direction = 0
                return

            next_floor = self.destination_floors[0]
            if next_floor > self.current_floor:
                self.direction = 1
                self.current_floor += 1
            elif next_floor < self.current_floor:
                self.direction = -1
                self.current_floor -= 1
            else:
                self.direction = 0
                self.destination_floors.pop(0)

    def add_destination(self, floor):
        with self.lock:
            if floor not in self.destination_floors:
                self.destination_floors.append(floor)
                self.destination_floors.sort(reverse=(self.direction == -1))

    def __str__(self):
        return f"Elevator {self.id}: Floor {self.current_floor}, Direction {'↑' if self.direction == 1 else '↓' if self.direction == -1 else '·'}, Destinations: {self.destination_floors}"

class Building:
    def __init__(self, num_elevators, num_floors):
        self.elevators = [Elevator(i, num_floors) for i in range(num_elevators)]
        self.num_floors = num_floors
        self.people_waiting = {floor: [] for floor in range(1, num_floors + 1)}
        self.time_of_day = 0  # 0-23 hours
        self.lock = Lock()

    def update_time(self):
        with self.lock:
            self.time_of_day = (self.time_of_day + 1) % 24

    def get_time_of_day(self):
        with self.lock:
            return self.time_of_day

    def spawn_people(self, max_people):
        time_of_day = self.get_time_of_day()
        if 8 <= time_of_day <= 9 or 17 <= time_of_day <= 18:  # Rush hours
            num_people = random.randint(1, max_people)
        elif 10 <= time_of_day <= 16:  # Daytime
            num_people = random.randint(0, max_people // 2)
        else:  # Night
            num_people = random.randint(0, max_people // 4)

        for _ in range(num_people):
            start_floor = random.randint(1, self.num_floors)
            end_floor = random.randint(1, self.num_floors)
            while end_floor == start_floor:
                end_floor = random.randint(1, self.num_floors)
            with self.lock:
                self.people_waiting[start_floor].append(end_floor)

    def assign_elevators(self):
        for floor, destinations in self.people_waiting.items():
            if not destinations:
                continue

            best_elevator = None
            min_distance = float('inf')

            for elevator in self.elevators:
                distance = abs(elevator.current_floor - floor)
                if (elevator.direction == 1 and floor >= elevator.current_floor) or \
                   (elevator.direction == -1 and floor <= elevator.current_floor) or \
                   elevator.direction == 0:
                    if distance < min_distance:
                        min_distance = distance
                        best_elevator = elevator

            if best_elevator:
                best_elevator.add_destination(floor)
                for dest in destinations:
                    best_elevator.add_destination(dest)
                with self.lock:
                    self.people_waiting[floor] = []

    def step(self):
        for elevator in self.elevators:
            elevator.move()
        self.assign_elevators()

    def status(self):
        status = []
        for elevator in self.elevators:
            status.append(str(elevator))
        for floor, people in self.people_waiting.items():
            if people:
                status.append(f"Floor {floor}: {len(people)} people waiting")
        return "\n".join(status)

def simulate(building, max_people, steps, delay=1):
    for step in range(steps):
        print(f"\n--- Time: {building.get_time_of_day()}:00, Step {step + 1} ---")
        building.spawn_people(max_people)
        building.step()
        print(building.status())
        building.update_time()
        time.sleep(delay)

if __name__ == "__main__":
